$$`,frontmatter:{},index:24,start:422,end:445,noteHTML:"",filepath:"/home/runner/work/slide/slide/optimization-in-deep-learning/slides.md",id:24,no:25},__clicksElements:[],__preloaded:!1}},{path:"26",name:"page-26",component:J$,meta:{slide:{raw:`
